<?php namespace App\Repositories\Hostel;use App\Repositories\BaseRepository;use App\Models\Hostel\HostelRoom;use Illuminate\Database\Eloquent\Collection;class HostelRoomRepository extends BaseRepository{    public function __construct(HostelRoom $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByHostel(int $hostelId): Collection    {        return $this->findByField('hostel_id', $hostelId);    }    public function findByRoomNo(string $roomNo): ?HostelRoom    {        return $this->query()->where('room_no', $roomNo)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('room_type', $type);    }    public function getAvailableRooms(int $hostelId): Collection    {        return $this->query()->where('hostel_id', $hostelId)->where('status', 'available')->get();    }    public function getOccupiedRooms(int $hostelId): Collection    {        return $this->query()->where('hostel_id', $hostelId)->where('status', 'occupied')->get();    }    public function getByFloor(int $floor): Collection    {        return $this->findByField('floor', $floor);    }    public function getByCapacity(int $minCapacity): Collection    {        return $this->query()->where('capacity', '>=', $minCapacity)->get();    }    public function searchRooms(string $keyword): Collection    {        return $this->query()->where('room_no', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function updateStatus(int $id, string $status): bool    {        return $this->update($id, ['status' => $status]);    }    public function countAvailableBeds(int $hostelId): int    {        return $this->query()->where('hostel_id', $hostelId)->where('status', 'available')->sum('capacity');    }}